patch:
--- include/FactorTable.hpp
@@ -68,7 +68,7 @@ class FactorTable : public BaseFactorTable
   /// Factor numbers <= y
   FactorTable(int64_t y, int threads)
   {
-    if (y > max())
+    if_unlikely(y > max())
       throw primecount_error("y must be <= FactorTable::max()");

     y = std::max<int64_t>(1, y);
--- include/FactorTableD.hpp
@@ -72,7 +72,7 @@ class FactorTableD : public BaseFactorTable
                int64_t z,
                int threads)
   {
-    if (z > max())
+    if_unlikely(z > max())
       throw primecount_error("z must be <= FactorTable::max()");

     z = std::max<int64_t>(1, z);
--- lib/primesieve/include/primesieve/malloc_vector.hpp
@@ -128,7 +128,7 @@ class malloc_vector
     // https://en.cppreference.com/w/c/memory/realloc
     T* new_array = (T*) realloc((void*) array_, new_capacity * sizeof(T));

-    if (!new_array)
+    if_unlikely(!new_array)
       throw std::bad_alloc();

     array_ = new_array;
--- lib/primesieve/src/MemoryPool.cpp
@@ -19,6 +19,7 @@
 #include <primesieve/MemoryPool.hpp>
 #include <primesieve/config.hpp>
 #include <primesieve/Bucket.hpp>
+#include <primesieve/macros.hpp>
 #include <primesieve/pod_vector.hpp>
 #include <primesieve/primesieve_error.hpp>

@@ -76,7 +77,7 @@ void MemoryPool::allocateBuckets()
   void* ptr = (void*) memory_.back().data();

   // Align pointer address to sizeof(Bucket)
-  if (!std::align(sizeof(Bucket), sizeof(Bucket), ptr, bytes))
+  if_unlikely(!std::align(sizeof(Bucket), sizeof(Bucket), ptr, bytes))
     throw primesieve_error("MemoryPool: failed to align memory!");

   count_ = bytes / sizeof(Bucket);
@@ -87,10 +88,9 @@ void MemoryPool::initBuckets(void* alignedPtr)
 {
   Bucket* buckets = (Bucket*) alignedPtr;

-  if ((std::size_t) buckets % sizeof(Bucket) != 0)
+  if_unlikely((std::size_t) buckets % sizeof(Bucket) != 0)
     throw primesieve_error("MemoryPool: failed to align memory!");
-
-  if (count_ < 10)
+  if_unlikely(count_ < 10)
     throw primesieve_error("MemoryPool: insufficient buckets allocated!");

   for (std::size_t i = 0; i < count_ - 1; i++)
--- src/deleglise-rivat/pi_deleglise_rivat.cpp
@@ -13,7 +13,7 @@
 ///        method, Revista do DETUA, vol. 4, no. 6, March 2006,
 ///        pp. 759-768.
 ///
-/// Copyright (C) 2021 Kim Walisch, <kim.walisch@gmail.com>
+/// Copyright (C) 2022 Kim Walisch, <kim.walisch@gmail.com>
 ///
 /// This file is distributed under the BSD License. See the COPYING
 /// file in the top level directory.
@@ -24,6 +24,7 @@
 #include <imath.hpp>
 #include <PhiTiny.hpp>
 #include <int128_t.hpp>
+#include <macros.hpp>
 #include <print.hpp>
 #include <S.hpp>
 #include <to_string.hpp>
@@ -112,7 +113,7 @@ int128_t pi_deleglise_rivat_128(int128_t x,
   double alpha = get_alpha_deleglise_rivat(x);
   maxint_t limit = get_max_x(alpha);

-  if (x > limit)
+  if_unlikely(x > limit)
     throw primecount_error("pi(x): x must be <= " + to_string(limit));

   int64_t y = (int64_t) (iroot<3>(x) * alpha);
--- src/gourdon/pi_gourdon.cpp
@@ -9,7 +9,7 @@
 ///        Xavier Gourdon formula:
 ///        pi(x) = A - B + C + D + Phi0 + Sigma
 ///
-/// Copyright (C) 2021 Kim Walisch, <kim.walisch@gmail.com>
+/// Copyright (C) 2022 Kim Walisch, <kim.walisch@gmail.com>
 ///
 /// This file is distributed under the BSD License. See the COPYING
 /// file in the top level directory.
@@ -19,6 +19,7 @@
 #include <primecount.hpp>
 #include <primecount-internal.hpp>
 #include <imath.hpp>
+#include <macros.hpp>
 #include <PhiTiny.hpp>
 #include <print.hpp>
 #include <to_string.hpp>
@@ -99,7 +100,7 @@ int128_t pi_gourdon_128(int128_t x,
   double alpha_z = alpha.second;
   maxint_t limit = get_max_x(alpha_y);

-  if (x > limit)
+  if_unlikely(x > limit)
     throw primecount_error("pi(x): x must be <= " + to_string(limit));

   int64_t x13 = iroot<3>(x);
--- src/nth_prime.cpp
@@ -14,6 +14,7 @@
 #include <PiTable.hpp>
 #include <pod_vector.hpp>
 #include <imath.hpp>
+#include <macros.hpp>

 #include <stdint.h>
 #include <string>
@@ -79,10 +80,9 @@ namespace primecount {
 ///
 int64_t nth_prime(int64_t n, int threads)
 {
-  if (n < 1)
+  if_unlikely(n < 1)
     throw primecount_error("nth_prime(n): n must be >= 1");
-
-  if (n > max_n)
+  if_unlikely(n > max_n)
     throw primecount_error("nth_prime(n): n must be <= " + std::to_string(max_n));

   // For tiny n <= 169

